---
import BaseLayout from '../../layouts/BaseLayout.astro';
import Hero from '../../components/Hero.astro';
import SermonCard from '../../components/SermonCard.astro';
import { getSermons } from '../../lib/sanity';

const title = 'Sermons | FICCC';
const description = 'Browse sermons from First Ithaca Chinese Christian Church. Filter by series and watch messages online.';

// ---------- CMS data (graceful fallback when Sanity is unreachable) ----------
let sermons: Awaited<ReturnType<typeof getSermons>> = [];

try {
  sermons = await getSermons('en');
} catch {
  // Sanity unreachable — continue with empty array
}

// ---------- Extract distinct series for filter ----------
const allSeries = [...new Set(sermons.map((s) => s.series).filter(Boolean))] as string[];
---

<BaseLayout title={title} description={description}>
  <main>
    <Hero
      title="Sermons"
      subtitle="Explore messages from our Sunday gatherings"
      backgroundImage="/images/hero-placeholder.svg"
    />

    {sermons.length > 0 ? (
      <section class="sermons-listing" aria-label="Sermon library">
        <div class="sermons-listing__inner">
          {allSeries.length > 0 && (
            <nav class="filter-bar" aria-label="Filter by series">
              <button class="filter-btn filter-btn--active" data-filter="all" type="button">
                All
              </button>
              {allSeries.map((series) => (
                <button class="filter-btn" data-filter={series} type="button">
                  {series}
                </button>
              ))}
            </nav>
          )}

          <div class="sermons-grid">
            {sermons.map((sermon) => (
              <div class="sermons-grid__item" data-series={sermon.series ?? ''}>
                <SermonCard
                  title={sermon.title}
                  speaker={sermon.speaker}
                  date={sermon.date}
                  series={sermon.series}
                  scripture={sermon.scripture}
                  href={sermon.slug?.current ? `/sermons/${sermon.slug.current}` : '#'}
                />
              </div>
            ))}
          </div>
        </div>
      </section>
    ) : (
      <section class="sermons-empty" aria-label="No sermons">
        <div class="sermons-empty__inner">
          <p class="sermons-empty__message">No sermons available at this time. Check back soon.</p>
        </div>
      </section>
    )}
  </main>
</BaseLayout>

<script>
  const filterBtns = document.querySelectorAll<HTMLButtonElement>('.filter-btn');
  const items = document.querySelectorAll<HTMLElement>('.sermons-grid__item');

  filterBtns.forEach((btn) => {
    btn.addEventListener('click', () => {
      const filter = btn.dataset.filter;

      // Toggle active class
      filterBtns.forEach((b) => b.classList.remove('filter-btn--active'));
      btn.classList.add('filter-btn--active');

      // Show/hide cards
      items.forEach((item) => {
        if (filter === 'all' || item.dataset.series === filter) {
          item.removeAttribute('hidden');
        } else {
          item.setAttribute('hidden', '');
        }
      });
    });
  });
</script>

<style>
  .sermons-listing {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-bg);
  }

  .sermons-listing__inner {
    max-width: var(--max-width);
    margin-inline: auto;
  }

  /* ---------- Filter bar ---------- */
  .filter-bar {
    display: flex;
    flex-wrap: wrap;
    gap: var(--space-2);
    margin-block-end: var(--space-10);
    justify-content: center;
  }

  .filter-btn {
    appearance: none;
    border: 1px solid var(--color-stone);
    background-color: var(--color-bg);
    color: var(--color-body);
    font-family: var(--font-body);
    font-size: var(--text-sm);
    font-weight: 500;
    padding: var(--space-2) var(--space-5);
    border-radius: 100vw;
    cursor: pointer;
    transition: background-color var(--transition), color var(--transition),
      border-color var(--transition);
  }

  .filter-btn:hover {
    border-color: var(--color-terracotta);
    color: var(--color-terracotta);
  }

  .filter-btn:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
  }

  .filter-btn--active {
    background-color: var(--color-terracotta);
    border-color: var(--color-terracotta);
    color: var(--color-bg);
  }

  .filter-btn--active:hover {
    color: var(--color-bg);
  }

  /* ---------- Sermon grid ---------- */
  .sermons-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: var(--space-8);
  }

  .sermons-grid__item[hidden] {
    display: none;
  }

  /* ---------- Empty state ---------- */
  .sermons-empty {
    padding: var(--space-20) var(--space-6);
    background-color: var(--color-bg);
  }

  .sermons-empty__inner {
    max-width: var(--max-width);
    margin-inline: auto;
    text-align: center;
  }

  .sermons-empty__message {
    font-family: var(--font-body);
    font-size: var(--text-lg);
    color: var(--color-body);
    line-height: var(--leading-relaxed);
  }

  /* ---------- Responsive ---------- */
  @media (max-width: 1024px) {
    .sermons-grid {
      grid-template-columns: repeat(2, 1fr);
    }
  }

  @media (max-width: 640px) {
    .sermons-grid {
      grid-template-columns: 1fr;
      gap: var(--space-6);
    }

    .sermons-listing {
      padding: var(--space-10) var(--space-4);
    }
  }
</style>

---
import BaseLayout from '../../layouts/BaseLayout.astro';
import Hero from '../../components/Hero.astro';
import YouTubeEmbed from '../../components/YouTubeEmbed.astro';
import { getSermons, type Sermon } from '../../lib/sanity';

export async function getStaticPaths() {
  let sermons: Sermon[] = [];

  try {
    sermons = await getSermons('en');
  } catch {
    // Sanity unreachable — return empty paths so build succeeds
  }

  return sermons
    .filter((s) => s.slug?.current)
    .map((sermon) => ({
      params: { slug: sermon.slug!.current },
      props: { sermon },
    }));
}

interface Props {
  sermon: Sermon;
}

const { sermon } = Astro.props;

const formattedDate = sermon.date
  ? new Date(sermon.date).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
    })
  : undefined;

const title = `${sermon.title} | Sermons | FICCC`;
---

<BaseLayout title={title}>
  <main>
    <Hero
      title={sermon.title}
      subtitle={sermon.series ?? undefined}
      backgroundImage="/images/hero-placeholder.svg"
    />

    <article class="sermon-detail">
      <div class="sermon-detail__inner">
        <a class="sermon-detail__back" href="/sermons">← Back to Sermons</a>

        <div class="sermon-detail__meta">
          {sermon.speaker && (
            <div class="sermon-detail__meta-item">
              <span class="sermon-detail__label">Speaker</span>
              <span class="sermon-detail__value">{sermon.speaker}</span>
            </div>
          )}
          {formattedDate && (
            <div class="sermon-detail__meta-item">
              <span class="sermon-detail__label">Date</span>
              <span class="sermon-detail__value">{formattedDate}</span>
            </div>
          )}
          {sermon.scripture && (
            <div class="sermon-detail__meta-item">
              <span class="sermon-detail__label">Scripture</span>
              <span class="sermon-detail__value">{sermon.scripture}</span>
            </div>
          )}
          {sermon.series && (
            <div class="sermon-detail__meta-item">
              <span class="sermon-detail__label">Series</span>
              <span class="sermon-detail__value">{sermon.series}</span>
            </div>
          )}
        </div>

        {sermon.videoId && (
          <div class="sermon-detail__video">
            <YouTubeEmbed videoId={sermon.videoId} />
          </div>
        )}
      </div>
    </article>
  </main>
</BaseLayout>

<style>
  .sermon-detail {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-bg);
  }

  .sermon-detail__inner {
    max-width: 48rem;
    margin-inline: auto;
  }

  /* ---------- Back link ---------- */
  .sermon-detail__back {
    display: inline-block;
    font-family: var(--font-body);
    font-size: var(--text-sm);
    font-weight: 500;
    color: var(--color-terracotta);
    text-decoration: none;
    margin-block-end: var(--space-8);
    transition: color var(--transition);
  }

  .sermon-detail__back:hover {
    color: #b3654b;
  }

  .sermon-detail__back:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
  }

  /* ---------- Metadata ---------- */
  .sermon-detail__meta {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: var(--space-6);
    margin-block-end: var(--space-10);
    padding: var(--space-8);
    background-color: var(--color-stone);
    border-radius: var(--radius-md);
  }

  .sermon-detail__meta-item {
    display: flex;
    flex-direction: column;
    gap: var(--space-1);
  }

  .sermon-detail__label {
    font-family: var(--font-body);
    font-size: var(--text-xs);
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: var(--color-body);
  }

  .sermon-detail__value {
    font-family: var(--font-body);
    font-size: var(--text-base);
    color: var(--color-ink);
  }

  /* ---------- Video ---------- */
  .sermon-detail__video {
    max-width: 100%;
  }

  /* ---------- Responsive ---------- */
  @media (max-width: 640px) {
    .sermon-detail {
      padding: var(--space-10) var(--space-4);
    }

    .sermon-detail__meta {
      grid-template-columns: 1fr;
      gap: var(--space-4);
      padding: var(--space-6);
    }
  }
</style>

