import BaseLayout from '../layouts/BaseLayout.astro';
import Hero from '../components/Hero.astro';

const title = 'Give | First Ithaca Chinese Christian Church';
const description =
  'Support the mission of First Ithaca Chinese Christian Church through your generous giving.';
---

<BaseLayout title={title} description={description}>
  <main>
    <Hero
      title="Give"
      subtitle="Your generosity makes a difference"
      backgroundImage="/images/hero-placeholder.svg"
    />

    <!-- Why We Give -->
    <section class="give-section" aria-label="Why We Give">
      <div class="give-section__inner">
        <h2 class="section-heading">Why We Give</h2>
        <div class="give-prose">
          <p>
            Giving is an act of worship and trust. When we give generously, we
            participate in God's work — supporting our church community, caring
            for those in need, and sharing the good news of Jesus Christ.
          </p>
          <blockquote class="give-verse">
            <p>
              "Each of you should give what you have decided in your heart to
              give, not reluctantly or under compulsion, for God loves a
              cheerful giver."
            </p>
            <cite>— 2 Corinthians 9:7 (NIV)</cite>
          </blockquote>
          <p>
            Whether it's your first time giving or you've been supporting our
            church for years, every gift — large or small — helps us continue
            serving our community in Ithaca and beyond. Thank you for your
            faithfulness.
          </p>
        </div>
      </div>
    </section>

    <!-- Ways to Give -->
    <section class="give-section give-section--alt" aria-label="Ways to Give">
      <div class="give-section__inner">
        <h2 class="section-heading">Ways to Give</h2>
        <div class="give-methods">

          <!-- Online via PayPal -->
          <div class="give-method">
            <div class="give-method__icon" aria-hidden="true">💳</div>
            <h3 class="give-method__title">Online via PayPal</h3>
            <p class="give-method__desc">
              Give securely online using PayPal. You can use a PayPal account,
              debit card, or credit card.
            </p>
            <a
              class="give-method__link"
              href="https://www.paypal.com/donate/?hosted_button_id=PLACEHOLDER"
              target="_blank"
              rel="noopener noreferrer"
            >
              Give with PayPal →
            </a>
          </div>

          <!-- By Check -->
          <div class="give-method">
            <div class="give-method__icon" aria-hidden="true">✉️</div>
            <h3 class="give-method__title">By Check</h3>
            <p class="give-method__desc">
              Make checks payable to <strong>First Ithaca Chinese Christian
              Church</strong> and mail to:
            </p>
            <address class="give-method__address">
              First Ithaca Chinese Christian Church<br />
              429 Mitchell Street<br />
              Ithaca, NY 14850
            </address>
          </div>

          <!-- In Person -->
          <div class="give-method">
            <div class="give-method__icon" aria-hidden="true">🏠</div>
            <h3 class="give-method__title">In Person</h3>
            <p class="give-method__desc">
              Offering envelopes are available at our Sunday service. You can
              place your gift in the offering box located in the sanctuary.
            </p>
            <p class="give-method__note">
              Sundays at 9:45 AM · 429 Mitchell Street
            </p>
          </div>

        </div>
      </div>
    </section>

    <!-- Questions -->
    <section class="give-section" aria-label="Questions about Giving">
      <div class="give-section__inner give-section__centered">
        <h2 class="section-heading">Questions?</h2>
        <p class="give-prose">
          If you have questions about giving, tax-deductible receipts, or other
          ways to support our church, please don't hesitate to
          <a href="/contact">contact us</a>. We're happy to help.
        </p>
      </div>
    </section>
  </main>
</BaseLayout>

